import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { fetchLatestMetrics } from '../services/api';

export default function VideoTable() {
  const [rows, setRows] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    fetchLatestMetrics()
      .then((res) => setRows(res.data))
      .catch(console.error);
  }, []);

  if (rows.length === 0) {
    return (
      <div className="card">
        <div className="empty-state">
          No metrics yet. Add videos and run a scrape first.
        </div>
      </div>
    );
  }

  return (
    <div className="card">
      <div className="card-header">
        <h2>Video Performance</h2>
      </div>
      <div className="table-wrap">
        <table>
          <thead>
            <tr>
              <th>Video URL</th>
              <th>Creator</th>
              <th>Campaign</th>
              <th>Platform</th>
              <th>Views</th>
              <th>Likes</th>
              <th>Shares</th>
              <th>Saves</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((r) => (
              <tr
                key={r._id}
                style={{ cursor: 'pointer' }}
                onClick={() => navigate(`/video/${r._id}`)}
              >
                <td className="url-cell">
                  <a
                    href={r.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    onClick={(e) => e.stopPropagation()}
                  >
                    {r.url}
                  </a>
                </td>
                <td>{r.video?.creator || '—'}</td>
                <td>{r.video?.campaign || '—'}</td>
                <td>
                  {r.video?.platform && (
                    <span className={`badge badge-${r.video.platform}`}>
                      {r.video.platform}
                    </span>
                  )}
                </td>
                <td>{Number(r.views).toLocaleString()}</td>
                <td>{Number(r.likes).toLocaleString()}</td>
                <td>{Number(r.shares).toLocaleString()}</td>
                <td>{Number(r.saves || 0).toLocaleString()}</td>
                <td>
                  {r.viral && <span className="badge badge-viral">VIRAL</span>}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
